      return `<svg fill="var(--icon-docker, #0db7ed)" class="w-4 h-4 shrink-0" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><title>Docker</title><path d="M13.983 11.078h2.119c.102 0 .186-.083.186-.188V9.006a.188.188 0 00-.186-.189h-2.119a.188.188 0 00-.185.189v1.884c0 .104.083.188.185.188zM19.171 9.9h2.117a.188.188 0 00.188-.188V7.83a.188.188 0 00-.188-.189h-2.117a.188.188 0 00-.187.189v1.882c0 .104.083.188.187.188zM16.615 9.9h2.12c.101 0 .187-.083.187-.188V7.83a.188.188 0 00-.187-.189h-2.12a.188.188 0 00-.188.189v1.882c0 .104.087.188.188.188zM13.983 9.9h2.119a.188.188 0 00.186-.188V7.83a.188.188 0 00-.186-.189h-2.119a.188.188 0 00-.185.189v1.882c0 .104.083.188.185.188zM13.983 8.72h2.119a.188.188 0 00.186-.188V6.646a.188.188 0 00-.186-.188h-2.119a.188.188 0 00-.185.188v1.886c0 .102.083.188.185.188zM11.375 11.078h2.118a.188.188 0 00.186-.188V9.006a.188.188 0 00-.186-.189h-2.118a.188.188 0 00-.186.189v1.884c0 .104.083.188.186.188zM11.375 9.9h2.118a.188.188 0 00.186-.188V7.83a.187.187 0 00-.186-.189h-2.118a.188.188 0 00-.186.189v1.882c0 .104.083.188.186.188zM8.761 11.078h2.119a.188.188 0 00.187-.188V9.006a.188.188 0 00-.187-.189H8.761a.188.188 0 00-.187.189v1.884c0 .104.083.188.187.188zM6.161 11.078h2.116a.188.188 0 00.188-.188V9.006a.188.188 0 00-.188-.189H6.161a.188.188 0 00-.188.189v1.884c0 .104.083.188.188.188zM23.993 11.578c-.24.765-.67 1.43-1.127 2.082-.48.687-1.05 1.3-1.685 1.879a6.91 6.91 0 01-2.912 1.54 9.652 9.652 0 01-2.528.302 1.83 1.83 0 00.015-.17c0-1.521-1.232-2.763-2.755-2.763s-2.756 1.242-2.756 2.763c0 .06.012.115.015.176a9.586 9.586 0 01-2.22-.244c-1.22-.441-2.26-1.261-3.04-2.247A6.9 6.9 0 01.127 12.35c.677-.04 1.334-.176 1.968-.41a9.23 9.23 0 003.04-.64 6.786 6.786 0 001.882-1.026c.224-.16.449-.33.673-.5h.063c.08.063.159.13.239.197 1.096.902 2.502 1.488 4.025 1.488h12.02l.06-.06a2.23 2.23 0 00.061-.634c0-.285-.015-.56-.044-.829z"/></svg>`;
    }

    let color = 'var(--icon-default, var(--text-secondary))';
    
    if (['css', 'scss', 'sass', 'less'].includes(ext)) {
      color = 'var(--icon-css, #3b82f6)';
    } else if (['txt', 'log', 'rst', 'text'].includes(ext)) {
      color = 'var(--icon-txt, #ec4899)';
    } else if (['java', 'jar', 'class'].includes(ext)) {
      color = 'var(--icon-java, #ea2d2e)';
    } else if (['kt', 'kts'].includes(ext)) {
      color = 'var(--icon-kotlin, #c084fc)';
    } else if (['cs', 'csharp'].includes(ext)) {
      color = 'var(--icon-csharp, #4ade80)';
    } else if (['png', 'jpg', 'jpeg', 'gif', 'svg', 'webp', 'ico'].includes(ext)) {
      color = 'var(--icon-image, #34d399)';
    } else if (['php'].includes(ext)) {
      color = 'var(--icon-php, #a78bfa)';
    } else if (['rb', 'ruby'].includes(ext)) {
      color = 'var(--icon-ruby, #f87171)';
    } else if (['sh', 'bash', 'zsh'].includes(ext)) {
      color = 'var(--icon-sh, #4ade80)';
    } else if (['bat', 'cmd', 'ps1'].includes(ext)) {
      color = 'var(--icon-cmd, #4ade80)';
    } else if (['yaml', 'yml', 'toml', 'ini', 'conf', 'config'].includes(ext)) {
      color = 'var(--icon-yaml, #fbbf24)';
    } else if (['xml', 'xhtml'].includes(ext)) {
      color = 'var(--icon-xml, #fbbf24)';
    } else if (['sql'].includes(ext)) {
      color = 'var(--icon-sql, #22d3ee)';
    } else if (['csv', 'tsv'].includes(ext)) {
      color = 'var(--icon-csv, #34d399)';
    } else if (['pdf'].includes(ext)) {
      color = 'var(--icon-pdf, #f87171)';
    } else if (['lp', 'asp'].includes(ext)) {
      color = 'var(--icon-asp, #c084fc)';
    } else if (['lock'].includes(ext)) {
      color = 'var(--icon-lock, #9ca3af)';
    } else if (['dart'].includes(ext)) {
      color = 'var(--icon-py, #3b82f6)';
    } else if (['swift'].includes(ext)) {
      color = 'var(--icon-html, #e34f26)';
    } else if (['lua'].includes(ext)) {
      color = 'var(--icon-ts, #3178c6)';
    } else if (lowerName.includes('.git') || ext === 'gitignore' || ext === 'gitattributes' || ext === 'gitmodules') {
      color = 'var(--icon-git, #f14e32)';
    } else if (lowerName.includes('.venv') || lowerName.includes('__pycache__') || lowerName.includes('python')) {
      color = 'var(--icon-py, #3b82f6)';
    }
    
    return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="${color}" class="w-4 h-4 shrink-0"><path d="M14 2H6c-1.1 0-1.99.9-1.99 2L4 20c0 1.1.89 2 1.99 2H18c1.1 0 2-.9 2-2V8l-6-6zm2 16H8v-2h8v2zm0-4H8v-2h8v2zm-3-5V3.5L18.5 9H13z"/></svg>`;
  }
</script>

